import Foundation

struct Author {
    let name: String
    let books: [Book]
}

struct Book {
    let title: String
    let authorName: String
}

let books = [
    Book(title: "SwiftData Book", authorName: "Ada"),
    Book(title: "Concurrency Guide", authorName: "Ada"),
    Book(title: "UI Patterns", authorName: "Kai")
]

let authors = Dictionary(grouping: books, by: { $0.authorName })
    .map { Author(name: $0.key, books: $0.value) }

for author in authors {
    print("\(author.name): \(author.books.map(\.title).joined(separator: ", "))")
}

