import Foundation

struct SchemaVersion: Comparable {
    let major: Int
    let minor: Int
    let patch: Int

    static func < (lhs: SchemaVersion, rhs: SchemaVersion) -> Bool {
        if lhs.major != rhs.major { return lhs.major < rhs.major }
        if lhs.minor != rhs.minor { return lhs.minor < rhs.minor }
        return lhs.patch < rhs.patch
    }
}

let v1 = SchemaVersion(major: 1, minor: 0, patch: 0)
let v2 = SchemaVersion(major: 2, minor: 1, patch: 0)
let v3 = SchemaVersion(major: 2, minor: 1, patch: 3)

print("v1 < v2: \(v1 < v2)")
print("v2 < v3: \(v2 < v3)")
print("Migration path: v1 -> v2 -> v3")

